def safe_float(x):
    try:
        return float(x)
    except Exception:
        return x


def format_value(x):
    if isinstance(x, (float, np.floating)):
        return f"{float(x):.6f}"
    if isinstance(x, (int, np.integer)):
        return str(int(x))
    return str(x)


def get_final_pair_value(seq):
    if seq is None or len(seq) == 0:
        return None
    item = seq[-1]
    if isinstance(item, (list, tuple, np.ndarray)) and len(item) >= 2:
        return safe_float(item[1])
    return safe_float(item)


def get_best_pair_value(seq, mode="max"):
    if seq is None or len(seq) == 0:
        return None
    values = []
    for item in seq:
        if isinstance(item, (list, tuple, np.ndarray)) and len(item) >= 2:
            values.append(safe_float(item[1]))
        else:
            values.append(safe_float(item))
    if len(values) == 0:
        return None
    return max(values) if mode == "max" else min(values)


def summarize_array(arr, prefix):
    arr = np.asarray(arr)
    if arr.size == 0:
        print(f"{prefix}: not available")
        return
    print(f"{prefix} mean: {format_value(arr.mean())}")
    print(f"{prefix} min: {format_value(arr.min())}")
    print(f"{prefix} max: {format_value(arr.max())}")


