import os
import numpy as np


def safe_float(value):
    if value is None:
        return None
    try:
        return float(value)
    except Exception:
        return value


def format_value(value):
    if value is None:
        return "None"
    if isinstance(value, (float, np.floating)):
        return f"{float(value):.6f}"
    if isinstance(value, (int, np.integer)):
        return str(int(value))
    if isinstance(value, np.ndarray):
        return np.array2string(value, precision=6, separator=", ")
    return str(value)


def get_final_metric(metric_list):
    if metric_list is None or len(metric_list) == 0:
        return None
    last_item = metric_list[-1]
    if isinstance(last_item, (list, tuple)) and len(last_item) >= 2:
        return safe_float(last_item[1])
    return safe_float(last_item)


def print_metric(metric_name, value):
    print(f"{metric_name}: {format_value(value)}")


def analyze_dataset(dataset_name, dataset_store):
    print(f"Dataset: {dataset_name}")

    lr_candidates = dataset_store.get("lr_candidates", None)
    if lr_candidates is not None:
        print_metric("learning rate candidates", lr_candidates)

    per_lr = dataset_store.get("per_lr", {})
    for lr_key, entry in per_lr.items():
        print(f"Dataset: {dataset_name} | learning rate setting: {lr_key}")

        base_lr = entry.get("base_lr", None)
        best_epoch = entry.get("best_epoch", None)
        best_val_acc = entry.get("best_val_acc", None)
        best_val_loss = entry.get("best_val_loss", None)

        train_accuracy_final = get_final_metric(
            entry.get("metrics", {}).get("train", [])
        )
        validation_accuracy_final = get_final_metric(
            entry.get("metrics", {}).get("val", [])
        )
        train_loss_final = get_final_metric(entry.get("losses", {}).get("train", []))
        validation_loss_final = get_final_metric(entry.get("losses", {}).get("val", []))

        stream_metrics = entry.get("metrics", {}).get("stream", [])
        stream_no_adapt = None
        stream_always_on = None
        stream_gated = None
        if len(stream_metrics) > 0 and isinstance(stream_metrics[0], dict):
            stream_no_adapt = stream_metrics[0].get("no_adapt", None)
            stream_always_on = stream_metrics[0].get("always_on", None)
            stream_gated = stream_metrics[0].get("gated", None)

        print_metric("base learning rate", base_lr)
        print_metric("best epoch", best_epoch)
        print_metric("final training accuracy", train_accuracy_final)
        print_metric("final training loss", train_loss_final)
        print_metric("final validation accuracy", validation_accuracy_final)
        print_metric("final validation loss", validation_loss_final)
        print_metric("best validation accuracy", best_val_acc)
        print_metric("best validation loss", best_val_loss)
        print_metric(
            "final stream shift-robust accuracy without adaptation", stream_no_adapt
        )
        print_metric(
            "final stream shift-robust accuracy with always-on adaptation",
            stream_always_on,
        )
        print_metric(
            "final stream shift-robust accuracy with gated adaptation", stream_gated
        )

        segment_accs = entry.get("segment_accs", {})
        if isinstance(segment_accs, dict):
            no_adapt_seg = segment_accs.get("no_adapt", None)
            always_on_seg = segment_accs.get("always_on", None)
            gated_seg = segment_accs.get("gated", None)

            if no_adapt_seg is not None and len(no_adapt_seg) > 0:
                print_metric(
                    "final segment accuracy without adaptation",
                    safe_float(no_adapt_seg[-1]),
                )
            if always_on_seg is not None and len(always_on_seg) > 0:
                print_metric(
                    "final segment accuracy with always-on adaptation",
                    safe_float(always_on_seg[-1]),
                )
            if gated_seg is not None and len(gated_seg) > 0:
                print_metric(
                    "final segment accuracy with gated adaptation",
                    safe_float(gated_seg[-1]),
                )

    summary = dataset_store.get("summary", {})
    if summary:
        print(f"Dataset: {dataset_name} | summary")
        print_metric(
            "best learning rate by validation accuracy",
            summary.get("best_lr_by_val", None),
        )
        print_metric("best validation accuracy", summary.get("best_val_acc", None))
        print_metric(
            "best learning rate by stream shift-robust accuracy without adaptation",
            summary.get("best_lr_by_stream_no_adapt", None),
        )
        print_metric(
            "best stream shift-robust accuracy without adaptation",
            summary.get("best_stream_no_adapt", None),
        )
        print_metric(
            "best learning rate by stream shift-robust accuracy with gated adaptation",
            summary.get("best_lr_by_stream_gated", None),
        )
        print_metric(
            "best stream shift-robust accuracy with gated adaptation",
            summary.get("best_stream_gated", None),
        )

    print("-" * 80)


