        return f"{float(value):.6f}"
    if isinstance(value, (int, np.integer)):
        return str(int(value))
    if isinstance(value, (list, tuple, np.ndarray)):
        arr = np.array(value)
        return np.array2string(arr, precision=6, separator=", ")
    return str(value)


def extract_last_metric_value(metric_series):
    if not metric_series:
        return None
    last_item = metric_series[-1]
    if isinstance(last_item, (list, tuple)) and len(last_item) >= 2:
        return last_item[1]
    return last_item


def print_summary_metrics(dataset_name, dataset_data):
    print(f"Dataset: {dataset_name}")

    summary = dataset_data.get("summary", {})
    if summary:
        batch_sizes = summary.get("batch_sizes", [])
        best_val_acc = summary.get("best_val_acc", [])
        final_val_acc = summary.get("final_val_acc", [])
        no_adapt = summary.get("shift_robust_acc_no_adapt", [])
        always_on = summary.get("shift_robust_acc_always_on", [])
        gated = summary.get("shift_robust_acc_gated", [])

        if batch_sizes:
            for i, batch_size in enumerate(batch_sizes):
                print(f"Configuration: train batch size = {format_value(batch_size)}")

                if i < len(best_val_acc):
                    print(f"Best validation accuracy: {format_value(best_val_acc[i])}")
                if i < len(final_val_acc):
                    print(
                        f"Final validation accuracy: {format_value(final_val_acc[i])}"
                    )
                if i < len(no_adapt):
                    print(
                        "Final shift-robust accuracy without adaptation: "
                        f"{format_value(no_adapt[i])}"
                    )
                if i < len(always_on):
                    print(
                        "Final shift-robust accuracy with always-on adaptation: "
                        f"{format_value(always_on[i])}"
                    )
                if i < len(gated):
                    print(
                        "Final shift-robust accuracy with confidence-gated adaptation: "
                        f"{format_value(gated[i])}"
                    )
                print()

    runs = dataset_data.get("runs", {})
    for run_name, run_data in runs.items():
