        metrics = run_data.get("metrics", {})
        losses = run_data.get("losses", {})

        final_train_accuracy = extract_last_metric_value(metrics.get("train", []))
        final_validation_accuracy = extract_last_metric_value(metrics.get("val", []))
        final_train_loss = extract_last_metric_value(losses.get("train", []))
        final_validation_loss = extract_last_metric_value(losses.get("val", []))

        if final_train_accuracy is not None:
            print(f"Final training accuracy: {format_value(final_train_accuracy)}")
        if final_validation_accuracy is not None:
            print(
                f"Final validation accuracy: {format_value(final_validation_accuracy)}"
            )
        if final_train_loss is not None:
            print(f"Final training loss: {format_value(final_train_loss)}")
        if final_validation_loss is not None:
            print(f"Final validation loss: {format_value(final_validation_loss)}")

        stream_metrics = metrics.get("stream", [])
        if stream_metrics:
            final_stream = stream_metrics[-1]
            if "no_adapt" in final_stream:
                print(
                    "Final shift-robust accuracy without adaptation: "
                    f"{format_value(final_stream['no_adapt'])}"
                )
            if "always_on" in final_stream:
                print(
                    "Final shift-robust accuracy with always-on adaptation: "
                    f"{format_value(final_stream['always_on'])}"
                )
            if "gated" in final_stream:
                print(
                    "Final shift-robust accuracy with confidence-gated adaptation: "
                    f"{format_value(final_stream['gated'])}"
                )

        segment_accs = run_data.get("segment_accs", {})
        if "no_adapt" in segment_accs and len(segment_accs["no_adapt"]) > 0:
