            print(
                "Final stream segment accuracy with always-on adaptation: "
                f"{format_value(segment_accs['always_on'][-1])}"
            )
        if "gated" in segment_accs and len(segment_accs["gated"]) > 0:
            print(
                "Final stream segment accuracy with confidence-gated adaptation: "
                f"{format_value(segment_accs['gated'][-1])}"
            )

        entropies = run_data.get("entropies", {})
        if "no_adapt" in entropies and len(entropies["no_adapt"]) > 0:
            print(
                "Final predictive entropy without adaptation: "
                f"{format_value(entropies['no_adapt'][-1])}"
