def to_float(value):
    if isinstance(value, np.generic):
        return float(value.item())
    return float(value)


def format_metric(name, value):
    if value is None:
        print(f"{name}: None")
    else:
        print(f"{name}: {value:.6f}")


def get_rank_number(rank_key):
    try:
        return int(str(rank_key).split("_")[-1])
    except Exception:
        return rank_key


def extract_final_metric(metric_array):
    if metric_array is None or len(metric_array) == 0:
        return None
    metric_array = np.asarray(metric_array)
    return to_float(metric_array[-1][1])


def extract_best_metric(metric_array):
    if metric_array is None or len(metric_array) == 0:
        return None
    metric_array = np.asarray(metric_array)
    return to_float(np.max(metric_array[:, 1]))


for experiment_name, experiment_group in experiment_data.items():
    for dataset_name, dataset_store in experiment_group.items():
